<p class="wp-block-paragraph">Understanding cultural norms and using body language and gestures correctly will strengthen your social interactions.</p>', '$.wp_published_at', '2025-11-01T14:29:03Z', '$.wp_modified_at', '2026-03-15T18:49:38Z', '$.featured_image', json('{"provider":"external","src":"/wp-content/uploads/2025/08/the-importance-of-body-language-and-gestures-in-turkey.webp","alt":"Body language and gestures importance in communication","title":"the-importance-of-body-language-and-gestures-in-turkey"}')) WHERE "collection" = 'posts' AND "id" = ( SELECT "live_revision_id" FROM "ec_posts" WHERE "deleted_at" IS NULL AND "status" = 'published' AND "locale" = 'en' AND "slug" = 'body-language-and-gestures-in-turkey' );
